1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = {
14	  type: string;
15	  material?: string;
16	  enchantment?: number;
17	  cursed?: boolean;
18	};
19	type Step = { op: "quote"; items: Item[] };
20	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const BLOCK_SIZE = 3;
24	const BLOCK_BASE_PREMIUM = 60;
25	
26	const itemBaseAndSurcharges = (item: Item): { base: number; surcharges: number } => {
27	  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
28	  const cursedSurcharge = item.cursed === true ? basePremium * 0.5 : 0;
29	  const highEnchantmentSurcharge =
30	    (item.enchantment ?? 0) >= 5 ? basePremium * 0.3 : 0;
31	  return { base: basePremium, surcharges: cursedSurcharge + highEnchantmentSurcharge };
32	};
33	
34	const componentGroupBasePremium = (type: string, count: number): number => {
35	  if (count === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
36	  return count * BASE_PREMIUM_BY_TYPE[type];
37	};
38	
39	const quotePremium = (items: Item[], customer: { yearsWithMHPCO: number }, isFollowUp: boolean): number => {
40	  const componentItems = items.filter((item) => COMPONENT_TYPES.has(item.type));
41	  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
42	
43	  const mainBaseTotal = mainItems.reduce((sum, item) => sum + itemBaseAndSurcharges(item).base, 0);
44	  const mainSurchargeTotal = mainItems.reduce((sum, item) => sum + itemBaseAndSurcharges(item).surcharges, 0);
45	
46	  const countsByType = componentItems.reduce<Record<string, number>>((acc, item) => {
47	    acc[item.type] = (acc[item.type] ?? 0) + 1;
48	    return acc;
49	  }, {});
50	
51	  const componentBaseTotal = Object.entries(countsByType).reduce(
52	    (sum, [type, count]) => sum + componentGroupBasePremium(type, count),
53	    0,
54	  );
55	
56	  const policyBase = mainBaseTotal + componentBaseTotal;
57	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
58	  const followUpDiscount = isFollowUp ? policyBase * 0.15 : 0;
59	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
60	
61	  return Math.ceil(policyBase + mainSurchargeTotal - loyaltyDiscount - followUpDiscount + firstInsuranceSurcharge + PROCESSING_FEE);
62	};
63	
64	type QuoteResult = { premium: number };
65	
66	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
67	  const results = scenario.steps.map((step, index) => ({ premium: quotePremium(step.items, scenario.customer, index > 0) }));
68	  return { results };
69	};
